+func TestCORSMiddleware(t *testing.T) {
+	tmpDir := t.TempDir()
+	handlers := &Handlers{}
+
+	cfg := DefaultConfig()
+	cfg.TokenPath = filepath.Join(tmpDir, ".api_token")
+
+	server, err := NewServer(cfg, handlers)
